patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,12 +1,12 @@
 module mux8 (
   input [7:0] data_a,
   input [7:0] data_b,
   input select,
   output [7:0] output_data
 );
   assign output_data = select ? data_b : data_a;
 endmodule

 module top;
   wire [7:0] bus1, bus2, result;
   wire sel;
-  mux8 inst (.data_a(bus1), .data_b(bus2), .sel(sel), .output_data(result));
+  mux8 inst (.data_a(bus1), .data_b(bus2), .select(sel), .output_data(result));
 endmodule

